#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;
const double eps=1e-5;

int n,len,a[N];
double s[N];

bool check(double x){
    double mn=0;
    for(int i=1;i<=n;i++){
        s[i]=s[i-1]+a[i]-x;
        if(i>len)
            mn=min(mn,s[i-len]);
        if(s[i]-mn>=0 && i>=len)
            return 1;
    }
    return 0;
}

int main(){
    scanf("%d%d",&n,&len);
    double l=0,r=0;
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        r=max(r,1.0*a[i]);
    }
    while(l+eps<r){
        double mid=(l+r)/2;
        if(check(mid))
            l=mid;
        else
            r=mid;
    }
    printf("%d",(int)(r*1000));
    return 0;
}
